import{c as e,Q as a,j as l,m as i}from"./chunks/framework.CQqJojvj.js";const f=JSON.parse('{"title":"杂谈","description":"","frontmatter":{},"headers":[],"relativePath":"misc/index.md","filePath":"misc/index.md","lastUpdated":null}'),d={name:"misc/index.md"};function r(n,t,s,o,c,y){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="杂谈" tabindex="-1">杂谈 <a class="header-anchor" href="#杂谈" aria-label="Permalink to &quot;杂谈&quot;">​</a></h1><blockquote><p>技术选型、性能对比、工程实践思考，以及面试过程中的反思与总结。</p></blockquote><hr><h2 id="arraylist-vs-linkedlist-什么时候用哪个" tabindex="-1">ArrayList vs LinkedList：什么时候用哪个？ <a class="header-anchor" href="#arraylist-vs-linkedlist-什么时候用哪个" aria-label="Permalink to &quot;ArrayList vs LinkedList：什么时候用哪个？&quot;">​</a></h2><p>这是一个经典的面试问题，但很多答案只说了一半。</p><h3 id="性能对比" tabindex="-1">性能对比 <a class="header-anchor" href="#性能对比" aria-label="Permalink to &quot;性能对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">操作</th><th style="text-align:left;">ArrayList</th><th style="text-align:left;">LinkedList</th></tr></thead><tbody><tr><td style="text-align:left;">尾部追加</td><td style="text-align:left;">O(1) 均摊（快）</td><td style="text-align:left;">O(1)</td></tr><tr><td style="text-align:left;">头部插入</td><td style="text-align:left;">O(n) — 需要整体移动</td><td style="text-align:left;">O(1)</td></tr><tr><td style="text-align:left;">中间插入</td><td style="text-align:left;">O(n) — 移动后半部分</td><td style="text-align:left;">O(n) — 先遍历到位置</td></tr><tr><td style="text-align:left;">随机访问</td><td style="text-align:left;">O(1) — 直接索引</td><td style="text-align:left;">O(n) — 遍历</td></tr><tr><td style="text-align:left;">内存占用</td><td style="text-align:left;">连续内存，单元素空间小</td><td style="text-align:left;">每个元素需要额外存储前后指针</td></tr><tr><td style="text-align:left;">CPU 缓存利用率</td><td style="text-align:left;">高（连续内存，缓存友好）</td><td style="text-align:left;">低（节点分散在堆中，缓存未命中多）</td></tr></tbody></table><h3 id="实际建议" tabindex="-1">实际建议 <a class="header-anchor" href="#实际建议" aria-label="Permalink to &quot;实际建议&quot;">​</a></h3><ol><li><strong>绝大多数场景用 ArrayList</strong> — 即使有插入需求，现代 CPU 的数组拷贝（<code>System.arraycopy</code>）也非常快</li><li><strong>极少场景用 LinkedList</strong> — 只有频繁在头部插入/删除时才考虑。典型场景：实现双端队列（Deque），但 JDK 已有 <code>ArrayDeque</code>，大多数情况下比 <code>LinkedList</code> 更好</li><li><strong>不要被 O(n) 迷惑</strong> — LinkedList 的 O(1) 插入隐藏了遍历定位的成本。对于中间插入，两者都是 O(n)</li></ol><h3 id="面试中的回答" tabindex="-1">面试中的回答 <a class="header-anchor" href="#面试中的回答" aria-label="Permalink to &quot;面试中的回答&quot;">​</a></h3><blockquote><p>&quot;在日常开发中我几乎总是用 ArrayList，因为它的内存连续性好、缓存友好，而且 <code>System.arraycopy</code> 是 native 方法，拷贝速度很快。LinkedList 只在确实需要频繁头部操作的场景才会考虑，但即使这种情况下 ArrayDeque 往往更合适。&quot;</p></blockquote>',11)])])}const x=e(d,[["render",r]]);export{f as __pageData,x as default};
